+fn decode_exact_usize_field(value: f64, min: usize) -> Option<usize> {
+    if !value.is_finite() || value.fract() != 0.0 || value < min as f64 || value > usize::MAX as f64
+    {
+        return None;
+    }
+    Some(value as usize)
+}
